figma.showUI(__html__, {
  width: 1020,
  height: 593,
  themeColors: true
});

function round(v){
  return Math.round(v);
}

function rgb(r,g,b){
  return {
    r:r/255,
    g:g/255,
    b:b/255
  };
}

function generateScale(base, ratio, count){

  const scale = [];
  let current = base;

  for(let i=0;i<count;i++){

    scale.unshift(
      round(current)
    );

    current = current * ratio;
  }

  return scale;
}

async function getMatchingFont(
  family,
  requestedStyle
){

  const fonts =
  await figma.listAvailableFontsAsync();

  const familyFonts =
  fonts.filter(
    f =>
    f.fontName.family === family
  );

  if(!familyFonts.length){
    return null;
  }

  const exact =
  familyFonts.find(
    f =>
    f.fontName.style
    .toLowerCase()
    .includes(
      requestedStyle
      .toLowerCase()
    )
  );

  if(exact){
    return exact.fontName;
  }

  return familyFonts[0].fontName;
}

figma.ui.onmessage = async(msg)=>{

  if(msg.type !== 'generate-system'){
    return;
  }

  try{

    const {
      fontFamily,
      selectedWeights,
      baseSize,
      ratio,
      device,
      variantCount,
      createDesign
    } = msg;

    const scale =
    generateScale(
      Number(baseSize),
      Number(ratio),
      Number(variantCount)
    );

    const created = [];

    for(const weight of selectedWeights){

      const fontName =
      await getMatchingFont(
        fontFamily,
        weight
      );

      if(!fontName){
        continue;
      }

      await figma.loadFontAsync(fontName);

      for(let i=0;i<scale.length;i++){

        const size = scale[i];

        const style =
        figma.createTextStyle();

        style.name =
        `${device}/${fontFamily}/H${i+1}/${weight}`;

        style.fontName =
        fontName;

        style.fontSize =
        size;

        style.lineHeight = {
          unit:'PIXELS',
          value:Math.round(size * 1.2)
        };

        created.push({
          styleId:style.id,
          level:`H${i+1}`,
          size,
          fontName,
          weight
        });
      }
    }

    if(!created.length){

      figma.notify(
        'No valid Figma fonts found'
      );

      return;
    }

    if(createDesign){

      const page =
      figma.createFrame();

      page.name =
      `${fontFamily} Typography Preview`;

      page.layoutMode =
      'VERTICAL';

      page.primaryAxisSizingMode =
      'AUTO';

      page.counterAxisSizingMode =
      'AUTO';

      page.itemSpacing = 64;

      page.paddingTop = 80;
      page.paddingBottom = 80;
      page.paddingLeft = 80;
      page.paddingRight = 80;

      page.fills = [{
        type:'SOLID',
        color:rgb(245,245,245)
      }];

      const title =
      figma.createText();

      await figma.loadFontAsync(
        created[0].fontName
      );

      title.characters =
      'Headings';

      title.fontName =
      created[0].fontName;

      title.fontSize = 28;

      title.fills = [{
        type:'SOLID',
        color:rgb(20,25,37)
      }];

      page.appendChild(title);

      for(const item of created){

        const section =
        figma.createFrame();

        section.layoutMode =
        'VERTICAL';

        section.primaryAxisSizingMode =
        'AUTO';

        section.counterAxisSizingMode =
        'AUTO';

        section.itemSpacing = 18;

        section.fills = [];

        const label =
        figma.createText();

        await figma.loadFontAsync(
          item.fontName
        );

        label.characters =
        item.level;

        label.fontName =
        item.fontName;

        label.fontSize = 22;

        label.fills = [{
          type:'SOLID',
          color:rgb(64,71,89)
        }];

        section.appendChild(label);

        const preview =
        figma.createText();

        preview.characters =
        'Typography';

        preview.fontName =
        item.fontName;

        preview.fontSize =
        item.size;

        preview.lineHeight = {
          unit:'PIXELS',
          value:Math.round(item.size * 1.2)
        };

        preview.textStyleId =
        item.styleId;

        preview.fills = [{
          type:'SOLID',
          color:rgb(10,15,31)
        }];

        section.appendChild(preview);

        const meta =
        figma.createText();

        meta.characters =
        `Size: ${item.size}px / ${(item.size/16).toFixed(2)}rem     Weight: ${item.weight}     Line Height: ${Math.round(item.size*1.2)}px`;

        meta.fontName =
        item.fontName;

        meta.fontSize = 14;

        meta.fills = [{
          type:'SOLID',
          color:rgb(64,71,89)
        }];

        section.appendChild(meta);

        page.appendChild(section);
      }

      figma.currentPage.appendChild(page);

      figma.viewport.scrollAndZoomIntoView([page]);
    }

    figma.notify(
      `Created ${created.length} typography styles`
    );

  }catch(err){

    console.error(err);

    figma.notify(
      'Typography generation failed'
    );
  }
};
